        # 1. OI Check
        oi = self.get_oi(symbol)
        if oi:
            details['oi'] = oi
            if direction == 'LONG':
                if oi['trend'] == 'RISING':
                    score += 1
                    reasons.append(f"OI rising +{oi['change_pct']:.1f}% ✅")
                elif oi['trend'] == 'FALLING':
                    score -= 1
                    reasons.append(f"OI falling {oi['change_pct']:.1f}% ❌ fake breakout risk")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")
            else:  # SHORT
                if oi['trend'] == 'FALLING':
                    score += 1
                    reasons.append(f"OI falling {oi['change_pct']:.1f}% ✅")
                elif oi['trend'] == 'RISING':
                    score -= 1
                    reasons.append(f"OI rising +{oi['change_pct']:.1f}% ❌")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")

        # 2. Funding Check
        funding = self.get_funding(symbol)
        if funding:
            details['funding'] = funding
            if direction == 'LONG' and funding['signal'] == 'OVERCROWDED_LONG':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.3f}% ❌ overcrowded LONG")
            elif direction == 'SHORT' and funding['signal'] == 'OVERCROWDED_SHORT':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.3f}% ❌ overcrowded SHORT")
            else:
                score += 1
                reasons.append(f"Funding {funding['rate_pct']:.3f}% ✅ normal")

        # 3. Liquidation Proximity Check
        liq = self.get_liquidation(symbol)
        if liq and liq['nearest_cluster']:
            details['liquidation'] = liq
            distance = abs(liq['nearest_cluster'] - current_price)
            distance_atr = distance / atr if atr > 0 else 999

            if distance_atr < LIQ_PROXIMITY_ATR:
                score -= 0.5
                reasons.append(f"Liq cluster dekat ({distance_atr:.1f} ATR) ⚠️ magnet risk")
            else:
                score += 0.5
                reasons.append(f"Liq clear ({distance_atr:.1f} ATR away) ✅")

        # Verdict
        pass_threshold = 1.5  # minimum score to pass
        passed = score >= pass_threshold

        return {
            'pass': passed,
            'score': score,
            'max_score': max_score,
            'reasons': reasons,
            'details': details,
        }

