VWAP Flow v4 — Binance Native Confirmation Layer
Replaces Kiyotaka API with direct Binance Futures endpoints.

Data sources:
- Open Interest: GET /fapi/v1/openInterest + /fapi/v1/openInterestHist
- Funding Rate:  GET /fapi/v1/fundingRate
- Long/Short:    GET /fapi/v1/globalLongShortAccountRatio (replaces liquidation)
- Taker Buy/Sell: GET /fapi/v1/takerlongshortRatio

No weight budget needed — Binance rate limit is generous (10-1200/min).
"""
import os
import time
import hmac
import hashlib
import json

try:
    import requests
except ImportError:
    requests = None

# ===== CONFIG =====
BINANCE_TESTNET = os.environ.get('TESTNET_BASE_URL', 'https://testnet.binancefuture.com')
BINANCE_FUTURES_URL = BINANCE_TESTNET.rstrip('/')

# Cache settings
OI_CACHE_TTL = 300         # 5 menit
OI_HIST_CACHE_TTL = 300    # 5 menit
FUNDING_CACHE_TTL = 300    # 5 menit (not 1 hour — funding updates every 8h but cheap to fetch)
LSR_CACHE_TTL = 300        # 5 menit
TAKER_CACHE_TTL = 300      # 5 menit

# Confirmation thresholds
OI_RISE_THRESHOLD = 0.5     # OI naik > 0.5% = genuine breakout
OI_DROP_THRESHOLD = -0.5    # OI turun > 0.5% = fake breakout
FUNDING_EXTREME_LONG = 0.05  # Funding > 0.05% = overcrowded LONG
FUNDING_EXTREME_SHORT = -0.05  # Funding < -0.05% = overcrowded SHORT
LSR_EXTREME_LONG = 2.0     # Long/Short ratio > 2.0 = overcrowded longs
LSR_EXTREME_SHORT = 0.5    # Long/Short ratio < 0.5 = overcrowded shorts


class KiyotakaData:
    """Binance native market data for breakout confirmation."""

    def __init__(self, api_key=None, api_secret=None):
        self.api_key = api_key or os.environ.get('TESTNET_API_KEY', '')
        self.api_secret = api_secret or os.environ.get('TESTNET_API_SECRET', '')
        self.base_url = BINANCE_FUTURES_URL
        self._cache = {}

        if not self.api_key:
            print("[CONFIRM] ⚠️ No API key — confirmation layer disabled")

    @property
    def enabled(self):
        return bool(self.api_key) and requests is not None

    def _get_cache(self, key, ttl):
        if key in self._cache:
            entry = self._cache[key]
            if time.time() - entry['time'] < ttl:
                return entry['data']
        return None

    def _set_cache(self, key, data):
        self._cache[key] = {'data': data, 'time': time.time()}

    def _request(self, endpoint, params=None, timeout_sec=10):
        """Make signed Binance API request."""
        if not self.enabled:
            return None

        try:
            url = f"{self.base_url}{endpoint}"
            resp = requests.get(url, params=params, timeout=timeout_sec)
            if resp.status_code == 200:
                return resp.json()
            else:
                print(f"[CONFIRM] HTTP {resp.status_code}: {resp.text[:100]}")
                return None
        except Exception as e:
            print(f"[CONFIRM] Request error: {e}")
            return None

    # ===== OPEN INTEREST (snapshot) =====
    def get_oi(self, symbol, period_sec=7200):
        """
        Fetch OI + history to calculate change.
        Returns: {'current': float, 'prev': float, 'change_pct': float, 'trend': str}
        """
        cache_key = f"oi_{symbol}"
        cached = self._get_cache(cache_key, OI_CACHE_TTL)
        if cached is not None:
            return cached

        # 1. Current OI
        data = self._request('/fapi/v1/openInterest', {'symbol': symbol})
        if not data:
            return None

        current_oi = float(data.get('openInterest', 0))

        # 2. OI history (period=1h, last N hours)
        hours = max(2, int(period_sec / 3600))
        hist = self._request('/fapi/v1/openInterestHist', {
            'symbol': symbol,
            'period': '1h',
            'limit': hours,
        })

        if not hist or len(hist) < 2:
            # Fallback: use current only, no trend
            result = {
                'current': current_oi,
                'prev': current_oi,
                'change_pct': 0,
                'trend': 'FLAT',
            }
            self._set_cache(cache_key, result)
            return result

        prev_oi = float(hist[-2].get('sumOpenInterest', current_oi))
        change_pct = ((current_oi - prev_oi) / prev_oi * 100) if prev_oi > 0 else 0

        if change_pct > OI_RISE_THRESHOLD:
            trend = 'RISING'
        elif change_pct < OI_DROP_THRESHOLD:
            trend = 'FALLING'
        else:
            trend = 'FLAT'

        result = {
            'current': current_oi,
            'prev': prev_oi,
            'change_pct': change_pct,
            'trend': trend,
        }
        self._set_cache(cache_key, result)
        return result

    # ===== FUNDING RATE =====
    def get_funding(self, symbol):
        """
        Fetch latest funding rate.
        Returns: {'rate': float, 'rate_pct': float, 'annualized': float, 'signal': str}
        """
        cache_key = f"funding_{symbol}"
        cached = self._get_cache(cache_key, FUNDING_CACHE_TTL)
        if cached is not None:
            return cached

        # Fetch last 3 funding rates
        data = self._request('/fapi/v1/fundingRate', {
            'symbol': symbol,
            'limit': 3,
        })

        if not data or not data:
            return None

        latest = data[-1]
        current_rate = float(latest.get('fundingRate', 0))
        annualized = current_rate * 3 * 365 * 100  # 3x per day → annualized %

        if current_rate > FUNDING_EXTREME_LONG:
            signal = 'OVERCROWDED_LONG'
        elif current_rate < FUNDING_EXTREME_SHORT:
            signal = 'OVERCROWDED_SHORT'
        else:
            signal = 'NEUTRAL'

        result = {
            'rate': current_rate,
            'rate_pct': current_rate * 100,
            'annualized': annualized,
            'signal': signal,
        }
        self._set_cache(cache_key, result)
        return result

    # ===== LONG/SHORT RATIO (replaces liquidation) =====
    def get_liquidation(self, symbol):
        """
        Fetch Long/Short ratio + Taker Buy/Sell ratio.
        These proxy for liquidation pressure:
        - LSR > 2.0 = too many longs → risk of long liquidation cascade
        - LSR < 0.5 = too many shorts → risk of short liquidation cascade
        - Taker Buy/Sell > 1.5 = aggressive buying (bullish)
        - Taker Buy/Sell < 0.67 = aggressive selling (bearish)
        Returns: {'lsr': float, 'lsr_trend': str, 'taker_ratio': float, 'taker_signal': str, ...}
        """
        cache_key = f"liq_{symbol}"
        cached = self._get_cache(cache_key, TAKER_CACHE_TTL)
        if cached is not None:
            return cached

        # 1. Long/Short Account Ratio
        lsr_data = self._request('/fapi/v1/globalLongShortAccountRatio', {
            'symbol': symbol,
            'period': '1h',
            'limit': 12,
        })

        # 2. Taker Buy/Sell Volume Ratio
        taker_data = self._request('/fapi/v1/takerlongshortRatio', {
            'symbol': symbol,
            'period': '1h',
            'limit': 12,
        })

        # Parse LSR
        lsr_current = 1.0
        lsr_trend = 'NEUTRAL'
        lsr_history = []
        if lsr_data:
            for item in lsr_data:
                lsr_history.append(float(item.get('longShortRatio', 1.0)))
            if lsr_history:
                lsr_current = lsr_history[-1]
                if len(lsr_history) >= 3:
                    avg_prev = sum(lsr_history[:-1]) / len(lsr_history[:-1])
                    if lsr_current > avg_prev * 1.1:
                        lsr_trend = 'RISING_LONG'
                    elif lsr_current < avg_prev * 0.9:
                        lsr_trend = 'RISING_SHORT'
                    else:
                        lsr_trend = 'NEUTRAL'

        # Parse Taker
        taker_current = 1.0
        taker_signal = 'NEUTRAL'
        if taker_data:
            for item in taker_data:
                ratio = float(item.get('buySellRatio', 1.0))
                taker_current = ratio  # latest
            if taker_current > 1.5:
                taker_signal = 'AGGRESSIVE_BUY'
            elif taker_current < 0.67:
                taker_signal = 'AGGRESSIVE_SELL'

        # Liquidation pressure assessment
        net_pressure = 0
        if lsr_current > LSR_EXTREME_LONG:
            net_pressure = -(lsr_current - 1)  # negative = long liquidation risk
        elif lsr_current < LSR_EXTREME_SHORT:
            net_pressure = (1 - lsr_current)   # positive = short liquidation risk

        result = {
            'lsr': lsr_current,
            'lsr_trend': lsr_trend,
            'taker_ratio': taker_current,
            'taker_signal': taker_signal,
            'net_pressure': net_pressure,
            'recent_buy': taker_current,
            'recent_sell': 1.0 / taker_current if taker_current > 0 else 1.0,
            'total_buy': 0,  # compat field
            'total_sell': 0,  # compat field
            'recent_pressure': net_pressure,
        }
        self._set_cache(cache_key, result)
        return result

    # ===== CONFIRMATION CHECK =====
    def check_breakout_confirmation(self, symbol, direction, current_price, atr):
        """
        Full confirmation check untuk breakout.
        Returns: {'pass': bool, 'score': float, 'max_score': int, 'reasons': list, 'details': dict}
        """
        if not self.enabled:
            return {'pass': True, 'score': 0, 'max_score': 3, 'reasons': ['Confirmation disabled (no API key)'], 'details': {}}

        score = 0
        max_score = 3
        reasons = []
        details = {}

        # 1. OI Check
        oi = self.get_oi(symbol)
        if oi:
            details['oi'] = oi
            if direction == 'LONG':
                if oi['trend'] == 'RISING':
                    score += 1
                    reasons.append(f"OI rising +{oi['change_pct']:.2f}% ✅")
                elif oi['trend'] == 'FALLING':
                    score -= 1
                    reasons.append(f"OI falling {oi['change_pct']:.2f}% ❌ fake breakout risk")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")
            else:  # SHORT
                if oi['trend'] == 'FALLING':
                    score += 1
                    reasons.append(f"OI falling {oi['change_pct']:.2f}% ✅")
                elif oi['trend'] == 'RISING':
                    score -= 1
                    reasons.append(f"OI rising +{oi['change_pct']:.2f}% ❌")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")

        # 2. Funding Check
        funding = self.get_funding(symbol)
        if funding:
            details['funding'] = funding
            if direction == 'LONG' and funding['signal'] == 'OVERCROWDED_LONG':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.4f}% ❌ overcrowded LONG")
            elif direction == 'SHORT' and funding['signal'] == 'OVERCROWDED_SHORT':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.4f}% ❌ overcrowded SHORT")
            else:
                score += 1
                reasons.append(f"Funding {funding['rate_pct']:.4f}% ✅ normal")

        # 3. Liquidation / Long-Short Ratio Check
        liq = self.get_liquidation(symbol)
        if liq:
            details['liquidation'] = liq
            lsr = liq['lsr']
            taker = liq['taker_ratio']

            if direction == 'LONG':
                if lsr > LSR_EXTREME_LONG:
                    score -= 0.5
                    reasons.append(f"LSR {lsr:.2f} ❌ overcrowded longs")
                elif lsr < 0.8:
                    score += 0.5
                    reasons.append(f"LSR {lsr:.2f} ✅ shorts crowded → squeeze potential")
                else:
                    score += 0.5
                    reasons.append(f"LSR {lsr:.2f} ✅ balanced")

                if taker > 1.3:
                    score += 0.5
                    reasons.append(f"Taker buy/sell {taker:.2f} ✅ aggressive buying")
                elif taker < 0.7:
                    score -= 0.5
                    reasons.append(f"Taker buy/sell {taker:.2f} ❌ aggressive selling")
            else:  # SHORT
                if lsr < LSR_EXTREME_SHORT:
                    score -= 0.5
                    reasons.append(f"LSR {lsr:.2f} ❌ overcrowded shorts")
                elif lsr > 1.2:
                    score += 0.5
                    reasons.append(f"LSR {lsr:.2f} ✅ longs crowded → dump potential")
                else:
                    score += 0.5
                    reasons.append(f"LSR {lsr:.2f} ✅ balanced")

                if taker < 0.7:
                    score += 0.5
                    reasons.append(f"Taker buy/sell {taker:.2f} ✅ aggressive selling")
                elif taker > 1.3:
                    score -= 0.5
                    reasons.append(f"Taker buy/sell {taker:.2f} ❌ aggressive buying")

        # Verdict
        pass_threshold = 1.5
        passed = score >= pass_threshold

        return {
            'pass': passed,
            'score': score,
            'max_score': max_score,
            'reasons': reasons,
            'details': details,
        }

    def get_weight_usage(self):
        """Compat: return cache stats (no weight budget needed for Binance)."""
        return {
            'used_this_min': 0,
            'limit_per_min': 1200,
            'cache_entries': len(self._cache),
        }


