{"path": "vwap_flow/kiyotaka.py", "content": """"
VWAP Flow v4 — Binance Confirmation Layer
Data sources dari Binance Futures API (testnet + fallback).

Endpoints used:
- Open Interest:     GET /fapi/v1/openInterest (testnet ✅)
- OI History:        Maintained locally (cache file) since mainnet blocked by ISP
- Funding Rate:      GET /fapi/v1/fundingRate (testnet ✅)
- Long/Short Ratio:  GET /fapi/v1/globalLongShortAccountRatio (mainnet, optional)
- Taker Buy/Sell:    GET /fapi/v1/takerlongshortRatio (mainnet, optional)

Note: ISP (Telkomsel) blocks mainnet Binance access. All primary data uses testnet.
LSR/Taker from mainnet are bonus — fail gracefully if unavailable.
"""
import os
import time
import json

try:
    import requests
except ImportError:
    requests = None

# ===== CONFIG =====
BINANCE_TESTNET_URL = os.environ.get('TESTNET_BASE_URL', 'https://testnet.binancefuture.com').rstrip('/')
BINANCE_MAINNET_URL = 'https://fapi.binance.com'
OI_HISTORY_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), '.oi_history.json')

# Cache settings
OI_CACHE_TTL = 300         # 5 min
FUNDING_CACHE_TTL = 300    # 5 min
LSR_CACHE_TTL = 300        # 5 min

# Confirmation thresholds
OI_RISE_THRESHOLD = 0.3     # OI naik > 0.3% = genuine breakout
OI_DROP_THRESHOLD = -0.3    # OI turun > 0.3% = fake breakout
FUNDING_EXTREME_LONG = 0.05   # Funding > 0.05% = overcrowded LONG
FUNDING_EXTREME_SHORT = -0.05 # Funding < -0.05% = overcrowded SHORT
LSR_EXTREME_LONG = 2.0
LSR_EXTREME_SHORT = 0.5


class KiyotakaData:
    """Binance market data for breakout confirmation."""

    def __init__(self, api_key=None, api_secret=None):
        self.api_key = api_key or os.environ.get('TESTNET_API_KEY', '')
        self.api_secret = api_secret or os.environ.get('TESTNET_API_SECRET', '')
        self._cache = {}
        self._oi_history = self._load_oi_history()

        if not self.api_key:
            print("[CONFIRM] ⚠️ No API key — confirmation layer disabled")

    @property
    def enabled(self):
        return bool(self.api_key) and requests is not None

    # ===== CACHE =====
    def _get_cache(self, key, ttl):
        if key in self._cache:
            entry = self._cache[key]
            if time.time() - entry['time'] < ttl:
                return entry['data']
        return None

    def _set_cache(self, key, data):
        self._cache[key] = {'data': data, 'time': time.time()}

    # ===== OI HISTORY (local file) =====
    def _load_oi_history(self):
        try:
            if os.path.exists(OI_HISTORY_FILE):
                with open(OI_HISTORY_FILE, 'r') as f:
                    return json.load(f)
        except Exception:
            pass
        return {}

    def _save_oi_history(self):
        try:
            with open(OI_HISTORY_FILE, 'w') as f:
                json.dump(self._oi_history, f)
        except Exception:
            pass

    # ===== HTTP REQUEST =====
    def _request(self, endpoint, params=None, timeout_sec=10, use_mainnet=False):
        if not self.enabled:
            return None
        try:
            base = BINANCE_MAINNET_URL if use_mainnet else BINANCE_TESTNET_URL
            url = f"{base}{endpoint}"
            resp = requests.get(url, params=params, timeout=timeout_sec,
                                verify=use_mainnet)  # skip SSL verify for mainnet (ISP cert issue)
            if resp.status_code == 200:
                return resp.json()
            else:
                print(f"[CONFIRM] HTTP {resp.status_code}: {resp.text[:100]}")
                return None
        except Exception as e:
            if use_mainnet:
                # Mainnet blocked by ISP is expected — silent skip
                pass
            else:
                print(f"[CONFIRM] Request error: {e}")
            return None

    # ===== OPEN INTEREST =====
    def get_oi(self, symbol, period_sec=7200):
        """
        Fetch OI + calculate change from local history.
        Returns: {'current': float, 'prev': float, 'change_pct': float, 'trend': str}
        """
        cache_key = f"oi_{symbol}"
        cached = self._get_cache(cache_key, OI_CACHE_TTL)
        if cached is not None:
            return cached

        # 1. Current OI from testnet
        data = self._request('/fapi/v1/openInterest', {'symbol': symbol})
        if not data:
            return None

        current_oi = float(data.get('openInterest', 0))

        # 2. Also try OI history from mainnet (bonus, may fail on ISP)
        hist = self._request('/fapi/v1/openInterestHist', {
            'symbol': symbol, 'period': '1h', 'limit': 8,
        }, use_mainnet=True)

        if hist and len(hist) >= 2:
            prev_oi = float(hist[-2].get('sumOpenInterest', current_oi))
        else:
            # Fallback: use local history file
            history = self._oi_history.get(symbol, [])
            if len(history) >= 2:
                prev_oi = history[-2]
            else:
                prev_oi = current_oi

        # Save to local history (keep last 48 entries = 48 hours)
        history = self._oi_history.get(symbol, [])
        history.append(current_oi)
        history = history[-48:]
        self._oi_history[symbol] = history
        self._save_oi_history()

        change_pct = ((current_oi - prev_oi) / prev_oi * 100) if prev_oi > 0 else 0

        if change_pct > OI_RISE_THRESHOLD:
            trend = 'RISING'
        elif change_pct < OI_DROP_THRESHOLD:
            trend = 'FALLING'
        else:
            trend = 'FLAT'

        result = {
            'current': current_oi,
            'prev': prev_oi,
            'change_pct': change_pct,
            'trend': trend,
        }
        self._set_cache(cache_key, result)
        return result

    # ===== FUNDING RATE =====
    def get_funding(self, symbol):
        """
        Fetch latest funding rate from testnet.
        Returns: {'rate': float, 'rate_pct': float, 'annualized': float, 'signal': str}
        """
        cache_key = f"funding_{symbol}"
        cached = self._get_cache(cache_key, FUNDING_CACHE_TTL)
        if cached is not None:
            return cached

        data = self._request('/fapi/v1/fundingRate', {
            'symbol': symbol, 'limit': 3,
        })

        if not data or not data:
            return None

        latest = data[-1]
        current_rate = float(latest.get('fundingRate', 0))
        annualized = current_rate * 3 * 365 * 100

        if current_rate > FUNDING_EXTREME_LONG:
            signal = 'OVERCROWDED_LONG'
        elif current_rate < FUNDING_EXTREME_SHORT:
            signal = 'OVERCROWDED_SHORT'
        else:
            signal = 'NEUTRAL'

        result = {
            'rate': current_rate,
            'rate_pct': current_rate * 100,
            'annualized': annualized,
            'signal': signal,
        }
        self._set_cache(cache_key, result)
        return result

    # ===== LONG/SHORT RATIO + TAKER (from mainnet, optional) =====
    def get_liquidation(self, symbol):
        """
        Fetch Long/Short ratio + Taker Buy/Sell from mainnet.
        If mainnet blocked by ISP, returns neutral defaults.
        Returns: {'lsr': float, 'lsr_trend': str, 'taker_ratio': float, 'taker_signal': str, ...}
        """
        cache_key = f"liq_{symbol}"
        cached = self._get_cache(cache_key, LSR_CACHE_TTL)
        if cached is not None:
            return cached

        # Try mainnet (may fail if ISP blocks)
        lsr_data = self._request('/fapi/v1/globalLongShortAccountRatio', {
            'symbol': symbol, 'period': '1h', 'limit': 12,
        }, use_mainnet=True)

        taker_data = self._request('/fapi/v1/takerlongshortRatio', {
            'symbol': symbol, 'period': '1h', 'limit': 12,
        }, use_mainnet=True)

        # Parse LSR
        lsr_current = 1.0
        lsr_trend = 'NEUTRAL'
        if lsr_data:
            lsr_history = [float(item.get('longShortRatio', 1.0)) for item in lsr_data]
            if lsr_history:
                lsr_current = lsr_history[-1]
                if len(lsr_history) >= 3:
                    avg_prev = sum(lsr_history[:-1]) / len(lsr_history[:-1])
                    if lsr_current > avg_prev * 1.1:
                        lsr_trend = 'RISING_LONG'
                    elif lsr_current < avg_prev * 0.9:
                        lsr_trend = 'RISING_SHORT'

        # Parse Taker
        taker_current = 1.0
        taker_signal = 'NEUTRAL'
        if taker_data:
            for item in taker_data:
                taker_current = float(item.get('buySellRatio', 1.0))
            if taker_current > 1.5:
                taker_signal = 'AGGRESSIVE_BUY'
            elif taker_current < 0.67:
                taker_signal = 'AGGRESSIVE_SELL'

        # Liquidation pressure
        net_pressure = 0
        if lsr_current > LSR_EXTREME_LONG:
            net_pressure = -(lsr_current - 1)
        elif lsr_current < LSR_EXTREME_SHORT:
            net_pressure = (1 - lsr_current)

        result = {
            'lsr': lsr_current,
            'lsr_trend': lsr_trend,
            'taker_ratio': taker_current,
            'taker_signal': taker_signal,
            'net_pressure': net_pressure,
            'recent_pressure': net_pressure,
            'total_buy': 0,
            'total_sell': 0,
            'recent_buy': taker_current,
            'recent_sell': 1.0 / taker_current if taker_current > 0 else 1.0,
            'available': bool(lsr_data or taker_data),  # flag: data available or defaults
        }
        self._set_cache(cache_key, result)
        return result

    # ===== CONFIRMATION CHECK =====
    def check_breakout_confirmation(self, symbol, direction, current_price, atr):
        """
        Full confirmation check.
        Returns: {'pass': bool, 'score': float, 'max_score': int, 'reasons': list, 'details': dict}
        """
        if not self.enabled:
            return {'pass': True, 'score': 0, 'max_score': 3,
                    'reasons': ['Confirmation disabled (no API key)'], 'details': {}}

        score = 0
        max_score = 3
        reasons = []
        details = {}

        # 1. OI Check (from testnet + local history)
        oi = self.get_oi(symbol)
        if oi:
            details['oi'] = oi
            if direction == 'LONG':
                if oi['trend'] == 'RISING':
                    score += 1
                    reasons.append(f"OI rising +{oi['change_pct']:.2f}% ✅")
                elif oi['trend'] == 'FALLING':
                    score -= 1
                    reasons.append(f"OI falling {oi['change_pct']:.2f}% ❌ fake breakout risk")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")
            else:  # SHORT
                if oi['trend'] == 'FALLING':
                    score += 1
                    reasons.append(f"OI falling {oi['change_pct']:.2f}% ✅")
                elif oi['trend'] == 'RISING':
                    score -= 1
                    reasons.append(f"OI rising +{oi['change_pct']:.2f}% ❌")
                else:
                    score += 0.5
                    reasons.append(f"OI flat ✅ neutral")

        # 2. Funding Check (from testnet)
        funding = self.get_funding(symbol)
        if funding:
            details['funding'] = funding
            if direction == 'LONG' and funding['signal'] == 'OVERCROWDED_LONG':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.4f}% ❌ overcrowded LONG")
            elif direction == 'SHORT' and funding['signal'] == 'OVERCROWDED_SHORT':
                score -= 1
                reasons.append(f"Funding extreme {funding['rate_pct']:.4f}% ❌ overcrowded SHORT")
            else:
                score += 1
                reasons.append(f"Funding {funding['rate_pct']:.4f}% ✅ normal")

        # 3. Long/Short Ratio + Taker (from mainnet, optional)
        liq = self.get_liquidation(symbol)
        if liq:
            details['liquidation'] = liq
            if not liq.get('available'):
                # Mainnet blocked — skip this check but don't penalize
                score += 0.5
                reasons.append("LSR/Taker unavailable (ISP blocked) ⚠️ neutral")
            else:
                lsr = liq['lsr']
                taker = liq['taker_ratio']

                if direction == 'LONG':
                    if lsr > LSR_EXTREME_LONG:
                        score -= 0.5
                        reasons.append(f"LSR {lsr:.2f} ❌ overcrowded longs")
                    elif lsr < 0.8:
                        score += 0.5
                        reasons.append(f"LSR {lsr:.2f} ✅ shorts crowded → squeeze")
                    else:
                        score += 0.5
                        reasons.append(f"LSR {lsr:.2f} ✅ balanced")

                    if taker > 1.3:
                        score += 0.5
                        reasons.append(f"Taker {taker:.2f} ✅ aggressive buying")
                    elif taker < 0.7:
                        score -= 0.5
                        reasons.append(f"Taker {taker:.2f} ❌ aggressive selling")
                else:  # SHORT
                    if lsr < LSR_EXTREME_SHORT:
                        score -= 0.5
                        reasons.append(f"LSR {lsr:.2f} ❌ overcrowded shorts")
                    elif lsr > 1.2:
                        score += 0.5
                        reasons.append(f"LSR {lsr:.2f} ✅ longs crowded → dump")
                    else:
                        score += 0.5
                        reasons.append(f"LSR {lsr:.2f} ✅ balanced")

                    if taker < 0.7:
                        score += 0.5
                        reasons.append(f"Taker {taker:.2f} ✅ aggressive selling")
                    elif taker > 1.3:
                        score -= 0.5
                        reasons.append(f"Taker {taker:.2f} ❌ aggressive buying")

        # Verdict
        pass_threshold = 1.5
        passed = score >= pass_threshold

        return {
            'pass': passed,
            'score': score,
            'max_score': max_score,
            'reasons': reasons,
            'details': details,
        }

    def get_weight_usage(self):
        """Compat: cache stats."""
        return {
            'used_this_min': 0,
            'limit_per_min': 1200,
            'cache_entries': len(self._cache),
        }


# ===== SINGLETON =====
_instance = None

def get_kiyotaka(api_key=None):
    """Get or create KiyotakaData singleton."""
    global _instance
    if _instance is None:
        _instance = KiyotakaData(api_key=api_key)
    return _instance
